// ==========================================
// 📘 INHERITANCE IN JAVASCRIPT
// ==========================================

// Parent Class
class User {
    constructor(username){
        this.username = username
    }

    logMe(){
        console.log(`USERNAME is ${this.username}`);
    }
}


// Child Class
class Teacher extends User{
    constructor(username, email, password){
        super(username)   // Call parent constructor
        this.email = email
        this.password = password
    }

    addCourse(){
        console.log(`A new course was added by ${this.username}`);
    }
}


// ==========================================
// 📘 Object Creation
// ==========================================

const chai = new Teacher(
    "chai",
    "chai@teacher.com",
    "123"
)

chai.logMe()           // Inherited method
// Output: USERNAME is chai

chai.addCourse()       // Child method

// ==========================================
// 📘 Parent Class Object
// ==========================================

const masalaChai = new User("masalaChai")
masalaChai.logMe()


// ==========================================
// 📘 instanceof Operator
// ==========================================

console.log(chai instanceof Teacher);   // true
console.log(chai instanceof User);      // true
console.log(masalaChai instanceof Teacher); // false


// ==========================================
// 📘 Key Concepts
// ==========================================

// extends     => Used for inheritance
// super()     => Calls parent constructor
// Child class inherits:
//   ✅ Properties
//   ✅ Methods from parent
// instanceof  => Checks inheritance relationship
